const items = $input.all().map(i => i.json);
const customerPhone = $('Trigger').item.json.body?.from || $('Trigger').item.json.from;

const staticData = $getWorkflowStaticData('global');
staticData[customerPhone] = { step: 'cart_building', items_list: items };

let text = '*Welcome to Ahmed Biryani House!*\n\n';
let currentCategory = '';

items.forEach((item, i) => {
  if (item.category !== currentCategory) {
    currentCategory = item.category;
    text += `\n*── ${currentCategory} ──*\n`;
  }
  text += `${i + 1}. ${item.item_name} — PKR ${item.price}\n`;
  if (item.description) text += `   _${item.description}_\n`;
});

text += '\n*How to order:*\n';
text += 'Type item numbers + qty. Example:\n';
text += '`1 x2, 3 x1`\n\n';
text += 'Reply *DONE* when finished.';

return [{ json: { message: text, to: customerPhone } }];
